function StorySegment({ segment }: { segment: { text: string; style?: string } }) {
    if (segment.style === "bold-italic") {
        return <span className="font-bold italic text-white">{segment.text}</span>;
    }
    if (segment.style === "highlight") {
        return <span className="font-bold text-white">{segment.text}</span>;
    }
    return <span>{segment.text}</span>;
}


